/**
 * lib/player-id-resolver.js
 *
 * Player ID Resolver: lookup players by slug or ESPN athlete ID,
 * returning { espnId, photo } or { slug, photo }.
 *
 * Data source: runtime player_id_bridge.json first, fallback read-only seed (generated by build-player-id-bridge.js)
 * Photo: ESPN CDN direct link, no API calls needed.
 */

const fs = require('fs');
const { resolveDataPath } = require('./data-resolver');

const BRIDGE_PATH = resolveDataPath('player_id_bridge.json');

let _bridge = null;

/**
 * Lazy load bridge data (with cache)
 */
function loadBridge() {
  if (_bridge) return _bridge;
  try {
    _bridge = JSON.parse(fs.readFileSync(BRIDGE_PATH, 'utf8'));
  } catch (e) {
    console.error('[player-id-resolver] Failed to load player_id_bridge.json:', e.message);
    _bridge = { bySlug: {}, byEspnId: {}, stats: {} };
  }
  return _bridge;
}

/**
 * Clear cache (for testing)
 */
function clearCache() {
  _bridge = null;
}

/**
 * Construct ESPN player photo URL
 * @param {string} espnAthleteId - ESPN athlete ID (6-digit numeric string)
 * @returns {string} Photo URL
 */
function espnPhotoUrl(espnAthleteId) {
  return `https://a.espncdn.com/combiner/i?img=/i/headshots/soccer/players/full/${espnAthleteId}.png`;
}

/**
 * Lookup ESPN athlete ID and photo by local slug ID
 *
 * @param {string} slug - Local player slug ID (e.g. "matej-kovar")
 * @returns {{ espnId: string, photo: string, name: string, teamCode: string } | null}
 */
function resolveBySlug(slug) {
  if (!slug) return null;
  const bridge = loadBridge();
  const entry = bridge.bySlug?.[slug];
  if (!entry) return null;
  return {
    espnId: entry.espnId,
    photo: espnPhotoUrl(entry.espnId),
    name: entry.nameSquad || entry.nameLineup || '',
    teamCode: entry.teamCode || '',
  };
}

/**
 * Lookup local slug ID and photo by ESPN athlete ID
 *
 * @param {string} espnId - ESPN athlete ID (e.g. "484012")
 * @returns {{ slug: string, photo: string, teamCode: string } | null}
 */
function resolveByEspnId(espnId) {
  if (!espnId) return null;
  const bridge = loadBridge();
  const entry = bridge.byEspnId?.[String(espnId)];
  if (!entry) return null;
  return {
    slug: entry.slug,
    photo: espnPhotoUrl(String(espnId)),
    teamCode: entry.teamCode || '',
  };
}

/**
 * Get ESPN player photo URL (no extra metadata needed, returns only photo link)
 *
 * @param {string} espnId - ESPN athlete ID
 * @returns {string} Photo URL
 */
function getPhotoByEspnId(espnId) {
  if (!espnId) return '';
  return espnPhotoUrl(String(espnId));
}

/**
 * Get bridge statistics
 * @returns {{ totalUniquePlayers: number, matched: number, unmatched: number, matchRate: number }}
 */
function getStats() {
  const bridge = loadBridge();
  return bridge.stats || { totalUniquePlayers: 0, matched: 0, unmatched: 0, matchRate: 0 };
}

/**
 * Batch lookup by slug (optimized, avoiding repeated I/O)
 *
 * @param {Object<string, string>} slugMap - { slugKey: slugValue } map
 * @returns {Object<string, { espnId: string, photo: string } | null>}
 */
function resolveBySlugBatch(slugMap) {
  const bridge = loadBridge();
  const result = {};
  for (const [key, slug] of Object.entries(slugMap)) {
    const entry = bridge.bySlug?.[slug];
    result[key] = entry
      ? { espnId: entry.espnId, photo: espnPhotoUrl(entry.espnId) }
      : null;
  }
  return result;
}

module.exports = {
  resolveBySlug,
  resolveByEspnId,
  getPhotoByEspnId,
  getStats,
  resolveBySlugBatch,
  clearCache,
  espnPhotoUrl,
};
